import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Bell, Shield, Moon, Sun, Lock, LogOut, ChevronRight } from 'lucide-react';

export default function Settings() {
  // Persistence logic: Remembers your choice even after refresh
  const [darkMode, setDarkMode] = useState(() => {
    return localStorage.getItem('theme') === 'dark';
  });
  
  const [pushNotifs, setPushNotifs] = useState(true);
  const [publicProfile, setPublicProfile] = useState(true);

  // Apply theme to the whole application
  useEffect(() => {
    const root = window.document.documentElement;
    if (darkMode) {
      root.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      root.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [darkMode]);

  // Design: Custom Toggle with smooth spring motion
  const Toggle = ({ enabled, setEnabled }) => (
    <button
      onClick={() => setEnabled(!enabled)}
      className={`w-14 h-7 rounded-full transition-all duration-500 relative ${
        enabled ? 'bg-teal-600 shadow-lg shadow-teal-600/20' : 'bg-slate-200'
      }`}
    >
      <motion.div
        animate={{ x: enabled ? 28 : 4 }}
        transition={{ type: "spring", stiffness: 500, damping: 30 }}
        className="absolute top-1 w-5 h-5 bg-white rounded-full shadow-sm"
      />
    </button>
  );

  return (
    <motion.div 
      initial={{ opacity: 0, y: 10 }} 
      animate={{ opacity: 1, y: 0 }} 
      className="p-10 max-w-4xl mx-auto space-y-10"
    >
      <div className="flex items-center gap-4">
        <div className="p-4 bg-teal-50 dark:bg-teal-900/30 text-teal-600 rounded-[24px]">
          <Lock size={32} />
        </div>
        <div>
          <h1 className="text-4xl font-black text-slate-900 dark:text-white tracking-tight">Account Settings</h1>
          <p className="text-slate-500 dark:text-slate-400 font-medium mt-1">Manage your privacy and security preferences.</p>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[40px] p-10 border border-slate-50 dark:border-slate-800 shadow-sm space-y-6 transition-colors duration-500">
        
        {/* Dark Mode Entry */}
        <div className="flex items-center justify-between p-6 bg-slate-50/50 dark:bg-slate-800/50 rounded-[32px] border border-transparent hover:border-teal-500/30 transition-all">
          <div className="flex items-center gap-6">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-colors ${darkMode ? 'bg-indigo-900/40 text-indigo-400' : 'bg-indigo-50 text-indigo-600'}`}>
              {darkMode ? <Moon size={28} /> : <Sun size={28} />}
            </div>
            <div>
              <h4 className="text-lg font-bold text-slate-900 dark:text-white">Dark Mode</h4>
              <p className="text-sm text-slate-400 font-medium">Switch the entire app to {darkMode ? 'light' : 'dark'} theme.</p>
            </div>
          </div>
          <Toggle enabled={darkMode} setEnabled={setDarkMode} />
        </div>

        {/* Public Profile */}
        <div className="flex items-center justify-between p-6 rounded-[32px] hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-all">
          <div className="flex items-center gap-6">
            <div className="w-14 h-14 bg-blue-50 dark:bg-blue-900/30 text-blue-600 rounded-2xl flex items-center justify-center">
              <Shield size={28} />
            </div>
            <div>
              <h4 className="text-lg font-bold text-slate-900 dark:text-white">Public Profile</h4>
              <p className="text-sm text-slate-400 font-medium">Allow others to see your skills and rating.</p>
            </div>
          </div>
          <Toggle enabled={publicProfile} setEnabled={setPublicProfile} />
        </div>

        {/* Push Notifications */}
        <div className="flex items-center justify-between p-6 rounded-[32px] hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-all">
          <div className="flex items-center gap-6">
            <div className="w-14 h-14 bg-teal-50 dark:bg-teal-900/30 text-teal-600 rounded-2xl flex items-center justify-center">
              <Bell size={28} />
            </div>
            <div>
              <h4 className="text-lg font-bold text-slate-900 dark:text-white">Push Notifications</h4>
              <p className="text-sm text-slate-400 font-medium">Receive alerts for new barter requests.</p>
            </div>
          </div>
          <Toggle enabled={pushNotifs} setEnabled={setPushNotifs} />
        </div>

        <hr className="border-slate-100 dark:border-slate-800 my-4" />

        {/* Logout Button */}
        <button className="w-full p-6 rounded-[32px] bg-red-50 dark:bg-red-900/10 text-red-600 font-black flex items-center justify-center gap-3 hover:bg-red-100 dark:hover:bg-red-900/20 transition-all active:scale-[0.98]">
          <LogOut size={22} /> Log Out from All Devices
        </button>
        
        <p className="text-center text-[10px] font-black text-slate-300 dark:text-slate-600 tracking-widest uppercase pt-4">
          WERTECH V0.1.0-BETA
        </p>
      </div>
    </motion.div>
  );
}
